// Validate incoming webhook payload
const body = $input.first().json.body || $input.first().json;

const transcript = body.transcript || '';
const anchor = body.anchor || {};

if (!transcript || transcript.trim().length < 500) {
  throw new Error('Validation failed: transcript missing or too short (minimum 500 chars)');
}

// Pass through validated payload
return [{
  json: {
    transcript: transcript.trim(),
    anchor: anchor,
    received_at: new Date().toISOString()
  }
}];

// ============================================================
// STAGE 1: DETERMINISTIC PRE-PROCESSOR
// Portrait Builder — SMRT Onboarding Pipeline
//
// Job: Split raw transcript into labeled topic segments and
// extract hard facts via pattern matching. No LLM. No guessing.
// Output feeds all 4 parallel Stage 2 extractors.
// ============================================================

const input = $input.first().json;
const transcript = input.transcript || '';
const anchor = input.anchor || {};

if (!transcript || transcript.trim().length < 500) {
  throw new Error('Transcript too short or missing — minimum 500 chars required');
}

// ── 1. HARD FACT EXTRACTION (regex, zero hallucination) ──────
const hardFacts = {};

// Email addresses
const emailMatches = transcript.match(/\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g);
hardFacts.emails = emailMatches ? [...new Set(emailMatches)] : [];

// Phone numbers (US formats)
const phoneMatches = transcript.match(/\b(\+?1[-.\s]?)?\(?\d{3}\)?[-.\s]?\d{3}[-.\s]?\d{4}\b/g);
hardFacts.phones = phoneMatches ? [...new Set(phoneMatches)] : [];

// ZIP codes
const zipMatches = transcript.match(/\b\d{5}(?:-\d{4})?\b/g);
hardFacts.zips = zipMatches ? [...new Set(zipMatches)] : [];

// Years (career-relevant: 1980–2030)
const yearMatches = transcript.match(/\b(19[89]\d|20[0-2]\d)\b/g);
hardFacts.years = yearMatches ? [...new Set(yearMatches)].sort() : [];

// Named states (abbreviated)
const statePattern = /\b(AL|AK|AZ|AR|CA|CO|CT|DE|FL|GA|HI|ID|IL|IN|IA|KS|KY|LA|ME|MD|MA|MI|MN|MS|MO|MT|NE|NV|NH|NJ|NM|NY|NC|ND|OH|OK|OR|PA|RI|SC|SD|TN|TX|UT|VT|VA|WA|WV|WI|WY)\b/g;
const stateMatches = transcript.match(statePattern);
hardFacts.states = stateMatches ? [...new Set(stateMatches)] : [];

// License numbers (common real estate formats)
const licenseMatches = transcript.match(/\b(license|lic\.?|#)\s*[A-Z0-9]{5,12}\b/gi);
hardFacts.licenses = licenseMatches ? [...new Set(licenseMatches)] : [];

// ── 2. SPEAKER TURN SPLITTING ────────────────────────────────
// Detect common transcript formats:
// "Luke: ...", "Agent: ...", "Speaker 1: ...", "[Luke]", "[Agent]"
// Also handles Fathom-style "Luke Gilbert (00:01:23): ..."

function splitIntoTurns(text) {
  const turns = [];

  // Try to detect speaker format
  const speakerPatterns = [
    // "Name (timestamp): text" — Fathom format
    /^([A-Za-z][A-Za-z\s]{1,30}?)\s*\(\d{2}:\d{2}(?::\d{2})?\)\s*:\s*/m,
    // "Name: text" — simple format
    /^([A-Za-z][A-Za-z\s]{1,20}?)\s*:\s*/m,
    // "[Name] text" — bracket format
    /^\[([A-Za-z][A-Za-z\s]{1,20}?)\]\s*/m,
  ];

  let detectedFormat = null;
  for (const pattern of speakerPatterns) {
    if (pattern.test(text)) {
      detectedFormat = pattern;
      break;
    }
  }

  if (!detectedFormat) {
    // No speaker labels detected — return as single block
    return [{ speaker: 'UNKNOWN', text: text.trim(), index: 0 }];
  }

  // Split by speaker turns using line-by-line approach
  const lines = text.split('\n');
  let currentSpeaker = null;
  let currentText = [];
  let turnIndex = 0;

  for (const line of lines) {
    // Check if this line starts a new speaker turn
    const fathomMatch = line.match(/^([A-Za-z][A-Za-z\s]{1,30}?)\s*\(\d{2}:\d{2}(?::\d{2})?\)\s*:\s*(.*)/);
    const simpleMatch = line.match(/^([A-Za-z][A-Za-z\s]{1,20}?)\s*:\s*(.*)/);
    const bracketMatch = line.match(/^\[([A-Za-z][A-Za-z\s]{1,20}?)\]\s*(.*)/);

    const match = fathomMatch || simpleMatch || bracketMatch;

    if (match) {
      // Save previous turn
      if (currentSpeaker && currentText.length > 0) {
        turns.push({
          speaker: currentSpeaker.trim().toUpperCase(),
          text: currentText.join(' ').trim(),
          index: turnIndex++
        });
      }
      currentSpeaker = match[1];
      currentText = [match[2] || ''];
    } else if (line.trim() && currentSpeaker) {
      currentText.push(line.trim());
    }
  }

  // Save last turn
  if (currentSpeaker && currentText.length > 0) {
    turns.push({
      speaker: currentSpeaker.trim().toUpperCase(),
      text: currentText.join(' ').trim(),
      index: turnIndex
    });
  }

  return turns;
}

const turns = splitIntoTurns(transcript);

// ── 3. IDENTIFY INTERVIEWER vs AGENT ─────────────────────────
// The interviewer is typically Luke / SMRT CSM
// The agent is the person being onboarded

const speakerCounts = {};
for (const turn of turns) {
  speakerCounts[turn.speaker] = (speakerCounts[turn.speaker] || 0) + turn.text.length;
}

// Sort by total text volume — agent usually speaks more
const speakers = Object.entries(speakerCounts).sort((a, b) => b[1] - a[1]);

// Heuristic: if "LUKE" or "SMRT" or "CSM" appears, that's the interviewer
let interviewerSpeaker = null;
let agentSpeaker = null;

for (const [speaker] of speakers) {
  const s = speaker.toLowerCase();
  if (s.includes('luke') || s.includes('smrt') || s.includes('csm') || s.includes('host')) {
    interviewerSpeaker = speaker;
  }
}

// Agent is the highest-volume non-interviewer speaker
for (const [speaker] of speakers) {
  if (speaker !== interviewerSpeaker) {
    agentSpeaker = speaker;
    break;
  }
}

// If we couldn't identify, use anchor or fall back
if (!agentSpeaker && anchor.expected_agent_name) {
  agentSpeaker = anchor.expected_agent_name.toUpperCase().split(' ')[0];
}

// Filter to agent turns only
const agentTurns = turns.filter(t => 
  agentSpeaker ? t.speaker === agentSpeaker : t.speaker !== interviewerSpeaker
);

// ── 4. TOPIC SEGMENT LABELING ────────────────────────────────
// Label each agent turn with one or more topic categories

const TOPIC_KEYWORDS = {
  origin_story: [
    'started', 'got into', 'began', 'first', 'license', 'licensed', 'career', 
    'before real estate', 'used to', 'prior to', 'originally', 'came from',
    'decided to', 'transition', 'switched', 'left', 'quit', 'recession', '2008',
    'broker', 'mentor', 'inspired', 'why i', 'how i got'
  ],
  market_geography: [
    'area', 'market', 'city', 'county', 'zip', 'neighborhood', 'region', 'territory',
    'serve', 'cover', 'focus', 'specialize in', 'work in', 'based in', 'located',
    'north', 'south', 'east', 'west', 'metro', 'suburb', 'rural', 'downtown',
    'boise', 'nampa', 'caldwell', 'meridian', 'eagle', 'kuna', 'star', 'middleton'
  ],
  client_types: [
    'client', 'buyer', 'seller', 'investor', 'first-time', 'first time', 'move-up',
    'downsiz', 'relocation', 'relo', 'luxury', 'military', 'veteran', 'divorce',
    'estate', 'probate', 'work with', 'help', 'serve', 'typical', 'ideal',
    'who i', 'my clients', 'people i'
  ],
  work_method: [
    'process', 'approach', 'method', 'system', 'how i', 'strategy', 'communicate',
    'text', 'call', 'email', 'respond', 'available', 'follow up', 'follow-up',
    'transaction', 'contract', 'offer', 'negotiat', 'represent', 'advocate',
    'explain', 'educate', 'walk through', 'step', 'timeline', 'closing'
  ],
  boundaries: [
    'won\'t', 'will not', 'don\'t', 'refuse', 'fire', 'fired', 'let go', 'walk away',
    'not willing', 'boundary', 'limit', 'tolerance', 'respect', 'treat', 'expect',
    'demand', 'disrespect', 'rude', 'scream', 'yell', 'abuse', 'right fit',
    'not a good fit', 'interview clients', 'qualify'
  ],
  competitive_edge: [
    'different', 'unique', 'stand out', 'better', 'advantage', 'value', 'why me',
    'why choose', 'what i offer', 'what sets', 'expertise', 'experience', 'track record',
    'result', 'sold', 'closed', 'volume', 'award', 'recognition', 'top', 'best',
    'proven', 'reputation', 'referral', 'repeat', 'testimonial'
  ],
  personal_background: [
    'family', 'kids', 'children', 'married', 'wife', 'husband', 'partner', 'dog',
    'hobby', 'hobbies', 'outside of work', 'personal', 'passion', 'love to',
    'enjoy', 'weekend', 'travel', 'sport', 'fitness', 'gym', 'run', 'golf',
    'grew up', 'born', 'raised', 'hometown', 'roots', 'community', 'volunteer',
    'church', 'faith', 'values', 'believe'
  ],
  qa_exchange: [] // Catch-all for direct Q&A — labeled by context
};

function labelTurn(turnText) {
  const text = turnText.toLowerCase();
  const labels = new Set();

  for (const [topic, keywords] of Object.entries(TOPIC_KEYWORDS)) {
    if (topic === 'qa_exchange') continue;
    for (const kw of keywords) {
      if (text.includes(kw)) {
        labels.add(topic);
        break;
      }
    }
  }

  // If no labels matched, mark as qa_exchange
  if (labels.size === 0) {
    labels.add('qa_exchange');
  }

  return [...labels];
}

const labeledTurns = agentTurns.map(turn => ({
  ...turn,
  topics: labelTurn(turn.text)
}));

// ── 5. BUILD SEGMENT BUNDLES ──────────────────────────────────
// Group turns by topic for each parallel extractor

function getSegmentText(topics) {
  const relevant = labeledTurns.filter(t => 
    t.topics.some(topic => topics.includes(topic))
  );
  return relevant.map(t => t.text).join('\n\n');
}

const segments = {
  // For Call A: full agent turns (operational fields need full context)
  operational: agentTurns.map(t => t.text).join('\n\n'),

  // For Call B: origin story + geography
  origin_and_geography: getSegmentText(['origin_story', 'market_geography', 'personal_background']),

  // For Call C: method + character
  method_and_character: getSegmentText(['client_types', 'work_method', 'boundaries', 'competitive_edge']),

  // For Call D: FAQ + personal
  faq_and_personal: getSegmentText(['qa_exchange', 'personal_background', 'origin_story']),

  // Full agent text for compilers
  full_agent_text: agentTurns.map(t => t.text).join('\n\n')
};

// Ensure no segment is empty — fall back to full agent text
for (const key of Object.keys(segments)) {
  if (!segments[key] || segments[key].trim().length < 100) {
    segments[key] = segments.full_agent_text;
  }
}

// ── 6. METADATA ───────────────────────────────────────────────
const meta = {
  total_turns: turns.length,
  agent_turns: agentTurns.length,
  interviewer_speaker: interviewerSpeaker,
  agent_speaker: agentSpeaker,
  speaker_detection_confidence: agentSpeaker ? 'detected' : 'fallback',
  topic_distribution: {},
  hard_facts: hardFacts,
  anchor: anchor
};

for (const turn of labeledTurns) {
  for (const topic of turn.topics) {
    meta.topic_distribution[topic] = (meta.topic_distribution[topic] || 0) + 1;
  }
}

return [{
  json: {
    segments,
    meta,
    transcript // pass through for Stage 2 calls that need full context
  }
}];

// ============================================================
// STAGE 3: MERGE + FLOOR CHECK
// Portrait Builder — SMRT Onboarding Pipeline
//
// Pulls from each named extractor node directly.
// Enforces 800-char floor per bio section.
// Flags violations for human review.
// ============================================================

function safeParseJSON(str) {
  if (!str) return {};
  const cleaned = str.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { return JSON.parse(jsonMatch[0]); } catch (e2) { return { _parse_error: str.substring(0, 200) }; }
    }
    return { _parse_error: str.substring(0, 200) };
  }
}

function extractFromNode(nodeName) {
  try {
    const item = $(nodeName).first().json;
    // n8n HTTP Request returns the OpenAI response directly
    const content = item.choices?.[0]?.message?.content || item.body?.choices?.[0]?.message?.content || '';
    if (content) return safeParseJSON(content);
    return item;
  } catch (e) {
    return { _node_error: `Could not read from ${nodeName}: ${e.message}` };
  }
}

// Pull from each extractor by name
const callA = extractFromNode('Call A \u2014 Operational Fields');
const callB = extractFromNode('Call B \u2014 Origin & Geography');
const callC = extractFromNode('Call C \u2014 Method & Character');
const callD = extractFromNode('Call D \u2014 FAQ & Personal');

// Get Stage 1 meta
const stage1 = $('Stage 1 \u2014 Pre-processor').first().json;
const meta = stage1.meta || {};

// -- FLOOR CHECK ---
const FLOORS = {
  background: 800,
  areas_served: 800,
  specialties: 1000,
  style: 800,
  faq: 1200
};

const bioSections = {
  background: callB.background || '',
  areas_served: callB.areas_served || '',
  specialties: callC.specialties || '',
  style: callC.style || '',
  faq: callD.faq || ''
};

const floorViolations = [];
const sectionLengths = {};

for (const [section, minLen] of Object.entries(FLOORS)) {
  const actual = bioSections[section].length;
  sectionLengths[section] = actual;
  if (actual < minLen) {
    floorViolations.push({
      section,
      actual_chars: actual,
      required_chars: minLen,
      shortfall: minLen - actual
    });
  }
}

const needsReview = floorViolations.length > 0;

// -- OPERATIONAL FIELDS MERGE ---
const operationalFields = {
  agent_full_name: callA.agent_full_name || meta.anchor?.expected_agent_name || null,
  agent_first_name: callA.agent_first_name || null,
  agent_last_name: callA.agent_last_name || null,
  agent_title: callA.agent_title || null,
  business_name: callA.business_name || null,
  agent_email: callA.agent_email || (meta.hard_facts?.emails?.[0] || null),
  agent_phone: callA.agent_phone || (meta.hard_facts?.phones?.[0] || null),
  company_website: callA.company_website || null,
  funnel_url: callA.funnel_url || null,
  office_address: callA.office_address || { street: null, city: null, state: null, zip: null },
  market_area: callA.market_area || null,
  market_name: callA.market_name || null,
  timezone: callA.timezone || null,
  specialties_keywords: callA.specialties_keywords || [],
  preferred_area_codes: callA.preferred_area_codes || [],
  coverage_cities: callA.coverage_cities || [],
  ai_coordinator_name: callA.ai_coordinator_name || null,
  agent_notes: callA.agent_notes || null,
  years_in_real_estate: callA.years_in_real_estate || null,
  license_year: callA.license_year || null
};

// -- MERGED RECORD ---
const mergedRecord = {
  ...operationalFields,

  bio: {
    background: bioSections.background,
    areas_served: bioSections.areas_served,
    specialties: bioSections.specialties,
    style: bioSections.style,
    faq: bioSections.faq,
    personal_note: callD.personal_note || null
  },

  quality: {
    section_lengths: sectionLengths,
    floor_violations: floorViolations,
    needs_review: needsReview,
    review_reasons: floorViolations.map(v => 
      `${v.section} is ${v.actual_chars} chars (minimum ${v.required_chars}, shortfall ${v.shortfall})`
    ),
    speaker_detection: meta.speaker_detection_confidence || 'unknown',
    agent_speaker_label: meta.agent_speaker || 'unknown',
    topic_distribution: meta.topic_distribution || {}
  },

  _meta: meta
};

return [{ json: mergedRecord }];

// ============================================================
// STAGE 5: NORMALIZE + PERSIST
// Portrait Builder — SMRT Onboarding Pipeline
//
// Maps extracted data to onboarding_requests schema.
// ============================================================

function safeParseJSON(str) {
  if (!str) return {};
  const cleaned = str.replace(/^```json\s*/i, '').replace(/\s*```$/i, '').trim();
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { return JSON.parse(jsonMatch[0]); } catch (e2) { return {}; }
    }
    return {};
  }
}

function extractFromNode(nodeName) {
  try {
    const item = $(nodeName).first().json;
    const content = item.choices?.[0]?.message?.content || item.body?.choices?.[0]?.message?.content || '';
    if (content) return safeParseJSON(content);
    return item;
  } catch (e) {
    return {};
  }
}

// Pull from named nodes
const mergedRecord = $('Stage 3 \u2014 Merge & Floor Check').first().json;
const portraitOutput = extractFromNode('Stage 4A \u2014 Portrait Compiler');
const characteristicsOutput = extractFromNode('Stage 4B \u2014 Characteristics Compiler');

const agentPortrait = portraitOutput.agent_portrait || '';
const agentCharacteristics = characteristicsOutput.agent_characteristics || '';
const personalityPrompt = characteristicsOutput.personality_prompt || '';

// -- NORMALIZE FIELDS ---
function normalizePhone(phone) {
  if (!phone) return null;
  const digits = phone.replace(/\D/g, '');
  if (digits.length === 10) return `+1${digits}`;
  if (digits.length === 11 && digits[0] === '1') return `+${digits}`;
  return phone;
}

function normalizeTimezone(tz) {
  if (!tz) return null;
  const tzMap = {
    'pacific': 'America/Los_Angeles', 'mountain': 'America/Denver',
    'central': 'America/Chicago', 'eastern': 'America/New_York',
    'pst': 'America/Los_Angeles', 'pdt': 'America/Los_Angeles',
    'mst': 'America/Denver', 'mdt': 'America/Denver',
    'cst': 'America/Chicago', 'cdt': 'America/Chicago',
    'est': 'America/New_York', 'edt': 'America/New_York'
  };
  const lower = tz.toLowerCase();
  for (const [key, val] of Object.entries(tzMap)) {
    if (lower.includes(key)) return val;
  }
  return tz;
}

// -- MAP TO onboarding_requests SCHEMA ---
// bio_template stores all bio sections as jsonb
const bioTemplate = {
  background: mergedRecord.bio?.background || '',
  areas_served: mergedRecord.bio?.areas_served || '',
  specialties: mergedRecord.bio?.specialties || '',
  style: mergedRecord.bio?.style || '',
  faq: mergedRecord.bio?.faq || '',
  personal_note: mergedRecord.bio?.personal_note || null,
  agent_portrait: agentPortrait,
  agent_characteristics: agentCharacteristics,
  extraction_quality: mergedRecord.quality || {}
};

const upsertPayload = {
  agent_name: mergedRecord.agent_full_name,
  agent_first_name: mergedRecord.agent_first_name,
  agent_last_name: mergedRecord.agent_last_name,
  agent_title: mergedRecord.agent_title || 'REALTOR\u00ae',
  business_name: mergedRecord.business_name,
  agent_email: mergedRecord.agent_email,
  agent_phone: normalizePhone(mergedRecord.agent_phone),
  agent_website: mergedRecord.company_website,
  agent_funnel_url: mergedRecord.funnel_url,
  office_address: mergedRecord.office_address,
  market_area: mergedRecord.market_area,
  market_name: mergedRecord.market_name,
  agent_timezone: normalizeTimezone(mergedRecord.timezone),
  specialties: mergedRecord.specialties_keywords || [],
  preferred_area_codes: mergedRecord.preferred_area_codes || [],
  coverage_cities: mergedRecord.coverage_cities || [],
  coordinator_name: mergedRecord.ai_coordinator_name || 'Jon',
  agent_notes: mergedRecord.agent_notes,
  personality_prompt: personalityPrompt,
  bio_template: bioTemplate,
  status: 'awaiting_launch'  // Valid: pending_ghl, awaiting_launch, launched, ghl_complete, failed
};

// -- WRITE TO SUPABASE ---
const SUPABASE_URL = $env.SUPABASE_URL || 'https://kfoijgcbkjeizxxyiwxv.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_KEY) {
  return [{
    json: {
      success: true,
      record_id: null,
      agent_name: upsertPayload.agent_full_name,
      status: upsertPayload.status,
      needs_review: mergedRecord.quality?.needs_review || false,
      review_reasons: mergedRecord.quality?.review_reasons || [],
      portrait_length: agentPortrait.length,
      characteristics_length: agentCharacteristics.length,
      _warning: 'SUPABASE_SERVICE_KEY not set — record not persisted'
    }
  }];
}

const upsertResponse = await globalThis.fetch(
  SUPABASE_URL + '/rest/v1/onboarding_requests',
  {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify(upsertPayload)
  }
);

const upsertBody = await upsertResponse.json();

if (!upsertResponse.ok) {
  throw new Error(`Supabase insert failed: ${upsertResponse.status} — ${JSON.stringify(upsertBody)}`);
}

const savedRecord = Array.isArray(upsertBody) ? upsertBody[0] : upsertBody;

return [{
  json: {
    success: true,
    record_id: savedRecord?.id || null,
    agent_name: upsertPayload.agent_full_name,
    status: upsertPayload.status,
    needs_review: mergedRecord.quality?.needs_review || false,
    review_reasons: mergedRecord.quality?.review_reasons || [],
    portrait_length: agentPortrait.length,
    characteristics_length: agentCharacteristics.length,
    pipeline_version: 'portrait_builder_v1',
    extracted_at: new Date().toISOString()
  }
}];
